conversation_deleted = 0
if first_conversation_id:
    try:
        convo_result = await conversations_collection.delete_one(
            {"user_id": user_id, "conversation_id": first_conversation_id}
        )
        conversation_deleted = convo_result.deleted_count
    except Exception as e:
        log.warning(f"[reset_onboarding] failed to delete conversation: {e}")

# Delete the LangGraph checkpointer thread for the seeded conversation.
# thread_id defaults to conversation_id (see build_agent_config). Without
# this, agent memory of the prior run survives reset.
checkpointer_thread_deleted = 0
if first_conversation_id:
    try:
        manager = await get_checkpointer_manager()
        await manager.get_checkpointer().adelete_thread(first_conversation_id)
        checkpointer_thread_deleted = 1
    except Exception as e:
        log.warning(
            f"[reset_onboarding] failed to delete checkpointer thread "
            f"{first_conversation_id}: {e}"
        )

# Disconnect every integration the user connected — onboarding offers
# OAuth connections (Gmail, Calendar, Slack, etc.) and a clean restart
# should not leave them attached. The modal warns the user about this.
integrations_disconnected = 0
try:
    cursor = user_integrations_collection.find(
        {"user_id": user_id}, {"integration_id": 1}
    )
    integration_ids = [doc["integration_id"] async for doc in cursor]
    for integration_id in integration_ids:
        try:
            await disconnect_integration(user_id, integration_id)
            integrations_disconnected += 1
        except Exception as e:
            log.warning(
                f"[reset_onboarding] failed to disconnect {integration_id}: {e}"
            )
except Exception as e:
    log.warning(f"[reset_onboarding] failed to list user integrations: {e}")

# Purge Mem0 memories accumulated during onboarding (email scan, social
# profiles, first conversation). Without this, the next onboarding pass
# would build on stale memories of the prior run.
memories_cleared = 0
try:
    cleared = await memory_service.delete_all_memories(user_id=user_id)
    memories_cleared = 1 if cleared else 0
except Exception as e:
    log.warning(f"[reset_onboarding] failed to clear memories: {e}")

# Unset the entire onboarding sub-document so the next run starts fresh.
await users_collection.update_one(
    {"_id": user_object_id},
    {
        "$unset": {"onboarding": ""},
        "$set": {"updated_at": datetime.now(timezone.utc)},
    },
)

log.set(
    onboarding={
        "operation": "reset",
        "workflows_deleted": workflows_deleted,
        "todos_deleted": todos_deleted,
        "conversation_deleted": conversation_deleted,
        "checkpointer_thread_deleted": checkpointer_thread_deleted,
        "integrations_disconnected": integrations_disconnected,
        "memories_cleared": memories_cleared,
    }
)
log.info(f"Onboarding reset complete for user {user_id}")

return {
    "workflows_deleted": workflows_deleted,
    "todos_deleted": todos_deleted,
    "conversation_deleted": conversation_deleted,
    "checkpointer_thread_deleted": checkpointer_thread_deleted,
    "integrations_disconnected": integrations_disconnected,
    "memories_cleared": memories_cleared,
}

